#!/usr/bin/env bash
# ╔═══════════════════════════════════════════════════════════════════╗
# ║        HOMURA  v1.0.0  —  USB Flash Utility                      ║
# ║        Self-contained launcher  ·  by wexloom                    ║
# ╠═══════════════════════════════════════════════════════════════════╣
# ║  Usage:   chmod +x homura.sh  &&  ./homura.sh                    ║
# ║  Distros: Arch · Ubuntu/Debian · Fedora/RHEL                     ║
# ║  Run as your NORMAL USER — do NOT run with sudo                  ║
# ╚═══════════════════════════════════════════════════════════════════╝

set -euo pipefail

# ── colours ────────────────────────────────────────────────────────────────
R='\033[0;31m' G='\033[0;32m' Y='\033[1;33m'
B='\033[0;34m' P='\033[0;35m' C='\033[0;36m'
W='\033[1;37m' D='\033[2m'   X='\033[0m'

info()  { echo -e "${C}  ◈  ${X}$*"; }
ok()    { echo -e "${G}  ✓  ${X}$*"; }
warn()  { echo -e "${Y}  ⚠  ${X}$*"; }
err()   { echo -e "${R}  ✗  ${X}$*" >&2; }
die()   { err "$*"; exit 1; }
sep()   { echo -e "${P}  ────────────────────────────────────────────${X}"; }

# ── banner ──────────────────────────────────────────────────────────────────
clear
echo
echo -e "${P}  ██╗  ██╗ ██████╗ ███╗   ███╗██╗   ██╗██████╗  █████╗${X}"
echo -e "${P}  ██║  ██║██╔═══██╗████╗ ████║██║   ██║██╔══██╗██╔══██╗${X}"
echo -e "${W}  ███████║██║   ██║██╔████╔██║██║   ██║██████╔╝███████║${X}"
echo -e "${P}  ██╔══██║██║   ██║██║╚██╔╝██║██║   ██║██╔══██╗██╔══██║${X}"
echo -e "${P}  ██║  ██║╚██████╔╝██║ ╚═╝ ██║╚██████╔╝██║  ██║██║  ██║${X}"
echo -e "${P}  ╚═╝  ╚═╝ ╚═════╝ ╚═╝     ╚═╝ ╚═════╝ ╚═╝  ╚═╝╚═╝  ╚═╝${X}"
echo
echo -e "  ${C}炎  USB Flash Utility  v1.0.0${X}   ${D}by wexloom${X}"
sep
echo

# ── safety: no root ─────────────────────────────────────────────────────────
if [[ $EUID -eq 0 ]]; then
    die "Do not run as root.\nRun as your normal user:  ./homura.sh"
fi

# ── detect distro ────────────────────────────────────────────────────────────
detect_distro() {
    if   command -v pacman &>/dev/null; then echo "arch"
    elif command -v apt    &>/dev/null; then echo "debian"
    elif command -v dnf    &>/dev/null; then echo "fedora"
    elif command -v yum    &>/dev/null; then echo "rhel"
    else echo "unknown"; fi
}
DISTRO=$(detect_distro)
info "Distro / package manager: ${W}${DISTRO}${X}"
echo

# ── install helper ───────────────────────────────────────────────────────────
install_pkg() {
    local arch="$1" deb="$2" fed="$3"
    case "$DISTRO" in
        arch)   sudo pacman -S --needed --noconfirm "$arch" ;;
        debian) sudo apt-get install -y "$deb" ;;
        fedora) sudo dnf install -y "$fed" ;;
        rhel)   sudo yum install -y "$fed" ;;
        *)      warn "Unknown distro — install manually"; return 1 ;;
    esac
}

# ── dep table:  binary|arch|deb|fedora ──────────────────────────────────────
DEPS=(
    "python3|python|python3|python3"
    "lsblk|util-linux|util-linux|util-linux"
    "parted|parted|parted|parted"
    "mkfs.fat|dosfstools|dosfstools|dosfstools"
    "mkfs.ntfs|ntfs-3g|ntfs-3g|ntfs-3g"
    "mkfs.exfat|exfatprogs|exfatprogs|exfatprogs"
    "badblocks|e2fsprogs|e2fsprogs|e2fsprogs"
    "syslinux|syslinux|syslinux|syslinux"
    "grub-install|grub|grub2-common|grub2"
    "wimlib-imagex|wimlib|wimtools|wimlib"
    "partprobe|parted|parted|parted"
    "blockdev|util-linux|util-linux|util-linux"
    "sync|coreutils|coreutils|coreutils"
)

# ── check deps ───────────────────────────────────────────────────────────────
sep
echo -e "  ${W}Checking dependencies...${X}"
sep
NEED_INSTALL=0

for entry in "${DEPS[@]}"; do
    IFS='|' read -r bin p_arch p_deb p_fed <<< "$entry"
    if command -v "$bin" &>/dev/null; then
        ok "$bin"
    else
        warn "$bin  ${D}not found${X}"
        NEED_INSTALL=1
    fi
done

# tkinter check
if python3 -c "import tkinter" &>/dev/null 2>&1; then
    ok "tkinter  (python module)"
else
    warn "tkinter  ${D}not found${X}"
    NEED_INSTALL=1
fi

echo

# ── install if needed ─────────────────────────────────────────────────────────
if [[ $NEED_INSTALL -eq 1 ]]; then
    sep
    echo -e "  ${Y}Installing missing packages...${X}"
    sep
    echo

    # Verify sudo
    if ! command -v sudo &>/dev/null; then
        die "sudo not found. Install it as root first."
    fi
    info "Requesting sudo authentication..."
    if ! sudo -v; then
        die "sudo authentication failed."
    fi
    ok "sudo cached."
    echo

    for entry in "${DEPS[@]}"; do
        IFS='|' read -r bin p_arch p_deb p_fed <<< "$entry"
        if ! command -v "$bin" &>/dev/null; then
            info "Installing: ${W}$p_arch${X} / ${W}$p_deb${X}..."
            if install_pkg "$p_arch" "$p_deb" "$p_fed" &>/dev/null; then
                ok "$bin  installed"
            else
                warn "$bin  install failed (some features may be limited)"
            fi
        fi
    done

    # tkinter
    if ! python3 -c "import tkinter" &>/dev/null 2>&1; then
        info "Installing tkinter..."
        case "$DISTRO" in
            arch)   sudo pacman -S --needed --noconfirm tk &>/dev/null ;;
            debian) sudo apt-get install -y python3-tk &>/dev/null ;;
            fedora) sudo dnf install -y python3-tkinter &>/dev/null ;;
            rhel)   sudo yum install -y python3-tkinter &>/dev/null ;;
        esac
    fi
fi

# final tkinter sanity check
if ! python3 -c "import tkinter" &>/dev/null 2>&1; then
    die "tkinter still unavailable.\nArch: sudo pacman -S tk\nUbuntu: sudo apt install python3-tk\nFedora: sudo dnf install python3-tkinter"
fi

echo
ok "All dependencies satisfied."
sep

# ── display environment check ─────────────────────────────────────────────────
echo
sep
echo -e "  ${W}Checking display environment...${X}"
sep

if [[ -n "${DISPLAY:-}" ]]; then
    ok "X11 display: ${DISPLAY}"
elif [[ -n "${WAYLAND_DISPLAY:-}" ]]; then
    ok "Wayland display: ${WAYLAND_DISPLAY}"
else
    warn "No \$DISPLAY or \$WAYLAND_DISPLAY set."
    warn "Launch from your desktop terminal emulator."
    echo
    read -r -p "  Continue anyway? (y/N): " ans
    [[ "${ans,,}" == "y" ]] || die "Aborted — please run from a graphical terminal."
fi

if [[ -n "${SSH_CLIENT:-}" || -n "${SSH_TTY:-}" ]]; then
    if [[ -z "${DISPLAY:-}" ]]; then
        die "SSH detected without X forwarding.\nUse:  ssh -X user@host\nThen re-run the launcher."
    fi
fi

echo
sep

# ── extract embedded app ─────────────────────────────────────────────────────
TMPDIR_APP=$(mktemp -d /tmp/homura_XXXXXX)
APP_PATH="$TMPDIR_APP/homura.py"

cleanup() { rm -rf "${TMPDIR_APP:-}" 2>/dev/null; }
trap cleanup EXIT INT TERM

info "Extracting app..."

python3 - "$APP_PATH" << 'DECODE_EOF'
import base64, sys
data = """"""
with open(sys.argv[1], 'wb') as f:
    f.write(base64.b64decode(data))
DECODE_EOF

chmod +x "$APP_PATH"
sed -i 's/self\._w/self\.cv_w/g; s/self\._h/self\.cv_h/g' "$APP_PATH"
ok "App ready at: $APP_PATH"
echo

# ── sudo tip ──────────────────────────────────────────────────────────────────
echo -e "  ${D}Tip: click  ⚡ Auth sudo  inside the app before flashing.${X}"
echo
sep
echo -e "\n  ${P}炎  Launching HOMURA...${X}\n"
sleep 0.4

# ── launch ────────────────────────────────────────────────────────────────────
python3 "$APP_PATH"
